-- 1. Insert Categories
ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, sort_order = EXCLUDED.sort_order;

-- 2. Insert Products
ON CONFLICT (id) DO UPDATE SET 
slug = EXCLUDED.slug, name = EXCLUDED.name, brand = EXCLUDED.brand, price = EXCLUDED.price, 
stock_status = EXCLUDED.stock_status, short_text = EXCLUDED.short_text, description = EXCLUDED.description;

-- 3. Insert Product Specs
DELETE FROM public.product_specs;


