INSERT INTO public.products (id, slug, category_slug, name, brand, price, stock_status, stock_quantity, short_text, "description", season, fish, water, method, material, badges, accent, sort_order, is_published) OVERRIDING SYSTEM VALUE VALUES
(101, 'narval-river-pike-802m', 'spinning', 'Narval River Pike 802M', 'Narval', '18 900 ₽', 'В наличии', 4, 'Универсальный спиннинг под щуку и судака, когда нужна дальность и контроль.', 'Хорошо чувствует джиг и воблеры, уверенно держит проводку и подходит для тех, кто хочет взять одну рабочую палку на большую часть сезона.', 'Весна / осень', 'Щука, судак', 'Река, водохранилище', 'Джиг, воблеры', 'Графит', '{"Хит","На щуку"}', 'linear-gradient(135deg, #183a43 0%, #2d4a3e 42%, #e0b57b 100%)', 10, true),
(102, 'maximus-advisor-jig-762ml', 'spinning', 'Maximus Advisor Jig 762ML', 'Maximus', '12 490 ₽', 'В наличии', 3, 'Легкий и отзывчивый вариант для тех, кто хочет чувствовать проводку лучше.', 'Подходит для аккуратной джиговой ловли и хорош как шаг вперед после базовых моделей.', 'Лето / осень', 'Окунь, судак, щука', 'Река, канал', 'Джиг', 'Высокомодульный графит', '{"Новинка"}', 'linear-gradient(135deg, #132932 0%, #4c6e5f 48%, #d9c4a1 100%)', 20, true),
(201, 'daiwa-legalis-lt-2500', 'reels', 'Daiwa Legalis LT 2500', 'Daiwa', '11 990 ₽', 'В наличии', 6, 'Надежная катушка на каждый день для универсального комплекта.', 'Хороший баланс между весом, плавностью и запасом прочности. Подойдет и новичку, и тому, кто ловит регулярно.', 'Круглый год', 'Щука, окунь', 'Берег, лодка', 'Спиннинг', 'Композит / алюминий', '{"Популярно"}', 'linear-gradient(135deg, #1f2a31 0%, #6d7f73 48%, #f0cf98 100%)', 30, true),
(202, 'dayo-caliber-2500', 'reels', 'Dayo Caliber 2500', 'Dayo', '6 490 ₽', 'В наличии', 8, 'Понятная и практичная катушка для первого надежного комплекта.', 'Если нужен уверенный старт без переплаты, это один из самых удобных вариантов для повседневной рыбалки.', 'Круглый год', 'Щука, окунь', 'Берег, лодка', 'Спиннинг', 'Алюминиевая шпуля', '{"Для новичка"}', 'linear-gradient(135deg, #26322f 0%, #728663 42%, #e6cfaa 100%)', 40, true),
(301, 'lucky-john-pike-hunter-set', 'lures', 'Lucky John Pike Hunter Set', 'Lucky John', 'от 390 ₽', 'В наличии', 18, 'Подборка силикона под щуку с рабочими цветами на сезон.', 'Удобный набор, когда хочется сразу взять несколько понятных приманок под активного хищника и не тратить время на десятки случайных позиций.', 'Весна / осень', 'Щука', 'Заливы, прибрежка', 'Джиг, офсет', 'Съедобный силикон', '{"Акция","На щуку"}', 'linear-gradient(135deg, #10272f 0%, #40626d 44%, #f2c97d 100%)', 50, true),
(302, 'strike-pro-inquisitor-110', 'lures', 'Strike Pro Inquisitor 110', 'Strike Pro', '1 180 ₽', 'В наличии', 11, 'Воблер под активный поиск щуки на мелководье и вдоль травы.', 'Любимая позиция для тех, кто хочет взять проверенный воблер без долгого чтения форумов и обзоров.', 'Лето / осень', 'Щука', 'Меляк, окна в траве', 'Твичинг', 'Пластик', '{"Хит"}', 'linear-gradient(135deg, #16252f 0%, #53706d 46%, #d8c3a4 100%)', 60, true),
(401, 'shimano-kairiki-012', 'lines', 'Shimano Kairiki 0.12', 'Shimano', '2 990 ₽', 'Уточнить наличие', 7, 'Тонкий информативный шнур для дальности и аккуратной анимации приманки.', 'Отличный выбор для тех, кто ценит чувствительность и хочет собрать деликатный спиннинговый комплект.', 'Лето / осень', 'Окунь, судак', 'Река, канал', 'Лайт, микроджиг', 'PE x8', '{"Популярно"}', 'linear-gradient(135deg, #172d35 0%, #718a84 40%, #d7c2a1 100%)', 70, true),
(402, 'sunline-super-pe-08', 'lines', 'Sunline Super PE 0.8', 'Sunline', '3 490 ₽', 'В наличии', 9, 'Крепкий шнур для повседневной ловли, когда важны надежность и стабильность.', 'Хорошо работает в универсальных сценариях и подходит для тех, кто не хочет компромиссов по ресурсу.', 'Круглый год', 'Щука, судак', 'Река, водохранилище', 'Универсальный спиннинг', 'PE', '{"В наличии"}', 'linear-gradient(135deg, #16262f 0%, #657970 46%, #efcea0 100%)', 80, true),
(501, 'norfin-flow-boots', 'gear', 'Norfin Flow Boots', 'Norfin', '7 890 ₽', 'В наличии', 5, 'Практичная обувь для береговой рыбалки и прохладного утра у воды.', 'Когда под ногами сырость, трава и рыхлый берег, комфорт часто важнее еще одной коробки приманок. Это как раз такой случай.', 'Весна / осень', 'Универсально', 'Берег, база', 'Выездной формат', 'EVA / текстиль', '{"Хит"}', 'linear-gradient(135deg, #3e3426 0%, #7f6245 46%, #e2d2b4 100%)', 90, true),
(502, 'alaskan-river-jacket', 'gear', 'Alaskan River Jacket', 'Alaskan', '13 700 ₽', 'Под заказ', 2, 'Куртка для ветра, брызг и долгих выездов к воде.', 'Если вы часто оказываетесь у воды ранним утром или в нестабильную погоду, это одна из самых полезных вещей в комплекте.', 'Весна / осень', 'Универсально', 'Берег, лодка', 'Выездной формат', 'Мембрана', '{"Под заказ"}', 'linear-gradient(135deg, #28312f 0%, #53685e 42%, #cfb291 100%)', 100, true),
(601, 'first-trip-box', 'gifts', 'Набор «Первый выезд»', 'ЩУКАРЬ', 'от 4 500 ₽', 'В наличии', 6, 'Подарочный набор для тех, кто только начинает рыбачить.', 'Собираем под бюджет, сезон и формат ловли. Понятный вариант, если хочется подарить полезную вещь, а не случайный сувенир.', 'Круглый год', 'Под задачу', 'Под задачу', 'Подбирается', 'Смешанный комплект', '{"Подарок","Для новичка"}', 'linear-gradient(135deg, #213739 0%, #5f7d61 46%, #f1d293 100%)', 110, true),
(602, 'pike-ready-box', 'gifts', 'Подборка «Готово на щуку»', 'ЩУКАРЬ', 'от 6 900 ₽', 'В наличии', 4, 'Сценарная подборка для тех, кто едет именно за рабочим набором на щуку.', 'Подходит как себе, так и в подарок. Удобный вариант, если не хочется тратить время на сбор комплекта с нуля.', 'Весна / осень', 'Щука', 'Берег, заливы', 'Спиннинг', 'Смешанный комплект', '{"На щуку","Подарок"}', 'linear-gradient(135deg, #17313a 0%, #4e7160 42%, #e8c484 100%)', 120, true)
